// 对全文各级标题及正文应用统一排版格式
var doc = Application.ActiveDocument;
var paragraphs = doc.getParagraphs();
var result = { total: 0, headings: 0, body: 0 };

for (var i = 0; i < paragraphs.length; i++) {
    var para = paragraphs[i];
    var range = para.getRange();
    var font = range.getFont();

    // 统一字体和字号
    font.setChineseFont("宋体");
    font.setFontSize(12); // 小四 = 12pt

    // 统一行距和段间距
    para.setLineSpacing(1, 20); // 固定值 20 磅
    para.setParagraphSpacingBefore(0.5 * 12 / 72); // 0.5 行 ≈ 6pt
    para.setParagraphSpacingAfter(0.5 * 12 / 72);

    // 判断是否为一二级标题
    var styleName = para.getRange().getStyle().getName();
    var isHeading1 = styleName.indexOf("标题 1") >= 0 || styleName.indexOf("Heading 1") >= 0;
    var isHeading2 = styleName.indexOf("标题 2") >= 0 || styleName.indexOf("Heading 2") >= 0;

    if (isHeading1 || isHeading2) {
        font.setBold(true);
        para.setFirstLineIndent(0);
        result.headings++;
    } else {
        // 正文首行缩进 2 字符
        para.setFirstLineIndent(2 * 12 / 72); // 2 字符 ≈ 24pt
        result.body++;
    }

    result.total++;
}

return result;

